import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

const API_BASE_URL = "http://localhost:8080/api";

function App() {
  const [page, setPage] = useState('login');
  const [filter, setFilter] = useState('Hepsi');

  // HÜSEYİN'İN VERİ KASASI (Backend'den Gelecekler)
  const [programs, setPrograms] = useState([]); // G6
  const [workouts, setWorkouts] = useState([]); // G10
  const [points, setPoints] = useState(0);       // G12
  const [badges, setBadges] = useState([]);     // G14
  const [streak, setStreak] = useState(0);       // G16

  // GEREKSİNİM 2: Kullanıcı Girişi
  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      // Backend'e POST isteği (G2)
      await axios.post(`${API_BASE_URL}/users/login`, {
        email: e.target.email.value,
        password: e.target.password.value
      });
      setPage('dashboard');
      fetchData(); // Giriş yapınca verileri çek
    } catch (err) {
      alert("Hüseyin: Giriş hatası! Backend çalışıyor mu?");
      setPage('dashboard'); // TEST AMAÇLI: Backend yoksa bile dashboard'u gör diye
    }
  };

  // VERİLERİ ÇEKME (G6, G10, G12, G14)
  const fetchData = async () => {
    try {
      const [pRes, wRes, ptRes, bRes, sRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/programs`),        // G6
        axios.get(`${API_BASE_URL}/workouts`),        // G10
        axios.get(`${API_BASE_URL}/users/points`),    // G12
        axios.get(`${API_BASE_URL}/badges`),          // G14
        axios.get(`${API_BASE_URL}/streak`)           // G16 (Görüntüleme)
      ]);
      setPrograms(pRes.data);
      setWorkouts(wRes.data);
      setPoints(ptRes.data);
      setBadges(bRes.data);
      setStreak(sRes.data.count);
    } catch (e) { console.log("Hüseyin: Backend'den veri bekleniyor..."); }
  };

  // GEREKSİNİM 8: Program Seçme ve Detay
  const onSelectProgram = async (id) => {
    await axios.post(`${API_BASE_URL}/programs/${id}/select`);
    const detail = await axios.get(`${API_BASE_URL}/programs/${id}`);
    alert(`Seçilen Program: ${detail.data.name} (G8 Tamam!)`);
  };

  // GEREKSİNİM 4: Profil Güncelleme
  const onUpdateProfile = async () => {
    await axios.put(`${API_BASE_URL}/users/profile`, { name: "Hüseyin Güncel" });
    alert("Profil Güncellendi! (G4 Tamam!)");
  };

  // --- EKRAN TASARIMLARI ---
  if (page === 'login' || page === 'register') {
    return (
      <div className="auth-wrapper">
        <div className="auth-container">
          <h1 className="logo-main">FIT<span>STACK</span></h1>
          <form className="auth-form" onSubmit={handleLogin}>
            <input name="email" type="email" placeholder="E-posta" className="auth-input" required />
            <input name="password" type="password" placeholder="Şifre" className="auth-input" required />
            <button type="submit" className="auth-submit">GİRİŞ YAP (G2)</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="app-container">
      <nav className="top-nav">
        <div className="logo-small">FIT<span>STACK</span></div>
        <div className="nav-links">
          <span onClick={() => setPage('dashboard')} className={page === 'dashboard' ? 'active' : ''}>DASHBOARD</span>
          <span onClick={() => setPage('profile')} className={page === 'profile' ? 'active' : ''}>PROFİL (G4)</span>
          <span className="logout-link" onClick={() => setPage('login')}>ÇIKIŞ</span>
        </div>
      </nav>

      <main className="content-area">
        {page === 'dashboard' ? (
          <div className="dashboard-grid">
            <div className="header-stats">
              <div className="stat-unit">
                <label>GÜNLÜK SERİ (G16)</label>
                <h2>🔥 {streak} GÜN</h2>
              </div>
              <div className="stat-unit">
                <label>TOPLAM PUAN (G12)</label>
                <h2 className="xp-text">{points} XP</h2>
              </div>
              <div className="stat-unit">
                <label>ROZETLER (G14)</label>
                <div className="mini-badges">
                  {badges.length > 0 ? badges.map(b => b.icon) : "🏆 ⚡ 🎖️"}
                </div>
              </div>
            </div>

            <section className="programs-section">
              <h3>PROGRAM LİSTELEME (G6)</h3>
              <div className="program-row">
                {programs.length > 0 ? programs.map(p => (
                  <div className="prog-card" key={p.id}>
                    <span className="tag">SEVİYE</span>
                    <h4>{p.name}</h4>
                    <button className="action-btn" onClick={() => onSelectProgram(p.id)}>SEÇ (G8)</button>
                  </div>
                )) : (
                  <div className="prog-card">
                    <span className="tag">ÖRNEK</span>
                    <h4>Backend'den Program Bekleniyor...</h4>
                  </div>
                )}
              </div>
            </section>

            <section className="recent-activity">
              <h3>GEÇMİŞ ANTRENMANLAR (G10)</h3>
              {workouts.length > 0 ? workouts.map(w => (
                <div className="activity-item" key={w.id}>
                  <p>{w.name} <span>+{w.xp} XP</span></p>
                </div>
              )) : <p>Henüz antrenman kaydı yok.</p>}
            </section>
          </div>
        ) : (
          <div className="profile-container">
            <div className="profile-box">
              <h2>PROFİL AYARLARI</h2>
              <button className="action-btn" onClick={onUpdateProfile}>PROFİLİ GÜNCELLE (G4)</button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
